(()=>{chrome.runtime.onMessage.addListener((r,o,e)=>{if(r.type==="SMOGON_FETCH")return fetch(r.url).then(t=>{if(!t.ok)throw new Error(`Smogon fetch failed with status: ${t.status}`);return r.isJson?t.json():t.text()}).then(t=>{e({success:!0,data:t})}).catch(t=>{console.error("[Gen 3 OU Tools] Failed to fetch data from Smogon with this error:",t),e({success:!1,error:t.message})}),!0});})();
